% 近似画像の表示
for idx = 1:nDics %[output:group:2dc8d076]
    yaprx = yaprxs{idx};
    dicname = dicnames(idx) %[output:38890f60] %[output:636aa702] %[output:418fa610] %[output:7240384e] %[output:4289e1bf] %[output:4d5b10cf] %[output:00031466] %[output:61d42163]
    file_yaprx = "../results/yaprx_" + replace(lower(dicname),' ','_') +".png";
